package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Given
        StringWriter out = new StringWriter();
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVPrinter csvPrinter = csvFormat.print(out);

        // Then
        assertNotNull(csvPrinter);
        // Add more assertions if needed
    }

    @Test
    public void testPrintWithException() throws IOException {
        // Given
        Appendable out = mock(Appendable.class);
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        IOException exception = new IOException("Error");

        // Mocking behavior to throw an exception
        doThrow(exception).when(out).append(any(CharSequence.class));

        // When
        IOException thrown = assertThrows(IOException.class, () -> csvFormat.print(out));

        // Then
        assertEquals("Error", thrown.getMessage());
    }
}
